const data = $input.all();

if (
  data.length === 1 &&
  Object.keys(data[0].json).length === 0
) {
  return {
    message: "✅ 미전송 건수 없음"
  };
}

// 많은 순 정렬 (선택)
data.sort((a, b) => b.json.total_cnt - a.json.total_cnt);

let output = "🚨 미전송 건수\n\n";

data.forEach(d => {
  const { pwn_nm, total_cnt } = d.json;

  output += `${pwn_nm} → ${Number(total_cnt).toLocaleString()}건\n`;
});

return {
  message: output
};

const data = $input.all()

if (
  data.length === 1 &&
  Object.keys(data[0].json).length === 0
) {
  return { message: "모든 화주사 미전송 건수 0건" };
}

const NAME_PADDING = 4;
const COUNT_PADDING = 4;

const HEADER_NAME = "화주사";
const HEADER_COUNT = "미전송 건수";

function getDisplayWidth(str) {
  return [...str].reduce((w, ch) => {
    if (ch.match(/[ㄱ-ㅎ|ㅏ-ㅣ|가-힣]/)) return w + 2;
    return w + 1;
  }, 0);
}

// 최대 길이 계산
const maxNameLength = Math.max(
  getDisplayWidth(HEADER_NAME),
  ...data.map(d => getDisplayWidth(d.json.pwn_nm))
);

const maxCountLength = Math.max(
  getDisplayWidth(HEADER_COUNT),
  ...data.map(d => getDisplayWidth(String(d.json.cnt)))
);

// WIDTH 산정
const NAME_WIDTH = maxNameLength + NAME_PADDING;
const COUNT_WIDTH = maxCountLength + COUNT_PADDING;
const TOTAL_WIDTH = NAME_WIDTH + COUNT_WIDTH;

// 출력
let output = "";
output += HEADER_NAME.padEnd(NAME_WIDTH - getDisplayWidth(HEADER_NAME)) + HEADER_COUNT.padStart(COUNT_WIDTH) + "\n";
output += "-".repeat(TOTAL_WIDTH) + "\n\n";

data.forEach(d => {
  const { pwn_nm, cnt } = d.json;

  output +=
    pwn_nm.padEnd(NAME_WIDTH - getDisplayWidth(pwn_nm)) +
    String(cnt).padStart(COUNT_WIDTH) +
    "\n";
});

return { message: output };

const now = new Date(new Date().toLocaleString("en-US", { timeZone: "Asia/Seoul" }));

const hour = now.getHours();

let baseDate = new Date(now);

if (hour < 6) {
  baseDate.setDate(baseDate.getDate() - 1);
}

baseDate.setHours(0, 0, 0, 0);

const nextDate = new Date(baseDate);
nextDate.setDate(nextDate.getDate() + 1);

function format(date) {
  return date.toISOString().slice(0, 19).replace('T', ' ');
}

return [
  {
    json: {
      now,
      start_dtm: format(baseDate),
      end_dtm: format(nextDate)
    }
  }
];
